class Solution:
    def maximumSum(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        def digit_sum(n):
            total = 0
            while n:
                total += n % 10
                n //= 10
            return total

        digit_sum_map = {}
        max_pair_sum = -1

        for num in nums:
            ds = digit_sum(num)

            if ds in digit_sum_map:
                # Found a pair with same digit sum
                max_pair_sum = max(max_pair_sum, num + digit_sum_map[ds])
                # Keep max for this digit sum
                digit_sum_map[ds] = max(digit_sum_map[ds], num)
            else:
                digit_sum_map[ds] = num

        return max_pair_sum
